import React from 'react';
import './App.css';

function App() {
  const handleClick = (section) => {
    alert(`מעבר אל: ${section}`);
  };

  const runEncryption = async () => {
    const folderPath = document.getElementById("folder-input").value;
    if (!folderPath) return alert("יש להזין נתיב תיקייה");

    try {
      const response = await fetch("http://127.0.0.1:5000/encrypt", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ folder: folderPath })
      });

      const result = await response.json();
      alert(`✅ סטטוס: ${result.status}\n📁 תיקייה: ${result.folder}`);
    } catch (error) {
      alert("❌ שגיאה בחיבור לשרת");
    }
  };
  const runDecryption = async () => {
    const folderPath = document.getElementById("folder-input").value;
    const keyHex = document.getElementById("key-input").value;
    if (!folderPath || !keyHex) return alert("אנא מלא את שני השדות");

    try {
      const response = await fetch("http://127.0.0.1:5000/decrypt", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ folder: folderPath, key: keyHex })
      });

      const result = await response.json();
      alert(`✅ פוענח: ${result.folder}`);
    } catch (error) {
      alert("❌ שגיאה בפיענוח");
    }
  };



  return (
    <div className="App">
      <h1 className="title">לומדת סימולציות Ransomware – <span style={{ color: "#ff1744" }}>ByteMe 🧠</span></h1>
      <div className="menu">
        <button onClick={() => handleClick("תיאוריה כללית")}>📘 תיאוריה כללית</button>
        <button onClick={runEncryption}>💣 הפעל הצפנה</button>
        <button onClick={runDecryption}>🔓 הפעל פיענוח</button>
        <button onClick={() => handleClick("תרגול מעשי")}>🧪 תרגול מעשי</button>
        <button onClick={() => handleClick("כלים נוספים")}>🛠 כלים נוספים</button>
        <button onClick={() => handleClick("סיכום")}>📊 סיכום וסטטיסטיקות</button>
      </div>
    </div>
  );
}

export default App;
